('economics:3-5-fiscal-policy:match:14308987', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fiscal policy”?", "options": ["Tax revenue exceeds government spending", "The government''s choices about taxation and spending", "Money given to encourage goods with positive externalities", "Outcomes a policy causes that the government did not intend"]}'::jsonb, '{"answer": 1, "explain": "“Fiscal policy” means: The government''s choices about taxation and spending"}'::jsonb),
('economics:3-5-fiscal-policy:match:2cbac857', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Direct tax”?", "options": ["A tax on income or wealth, paid by the person liable for it", "What the government must pay on money it has borrowed", "Money given to encourage goods with positive externalities", "Government spending exceeds tax revenue — the gap is borrowed"]}'::jsonb, '{"answer": 0, "explain": "“Direct tax” means: A tax on income or wealth, paid by the person liable for it"}'::jsonb),
('economics:3-5-fiscal-policy:match:9b5de289', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Indirect tax”?", "options": ["A tax on spending, collected and passed on by the seller", "Money given to encourage goods with positive externalities", "Government borrowing and spending displacing private sector activity", "Government spending exceeds tax revenue — the gap is borrowed"]}'::jsonb, '{"answer": 0, "explain": "“Indirect tax” means: A tax on spending, collected and passed on by the seller"}'::jsonb),
('economics:3-5-fiscal-policy:match:ba798cde', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Budget deficit”?", "options": ["Money given to encourage goods with positive externalities", "Government borrowing and spending displacing private sector activity", "Government spending exceeds tax revenue — the gap is borrowed", "An indirect tax on goods like tobacco, alcohol and fuel"]}'::jsonb, '{"answer": 2, "explain": "“Budget deficit” means: Government spending exceeds tax revenue — the gap is borrowed"}'::jsonb),
('economics:3-5-fiscal-policy:match:39ebfe97', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Budget surplus”?", "options": ["The government''s choices about taxation and spending", "Tax revenue exceeds government spending", "Government spending exceeds tax revenue — the gap is borrowed", "A tax on spending, collected and passed on by the seller"]}'::jsonb, '{"answer": 1, "explain": "“Budget surplus” means: Tax revenue exceeds government spending"}'::jsonb),
('economics:3-5-fiscal-policy:match:7db70cd9', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Balanced budget”?", "options": ["Tax revenue exceeds government spending", "Tax revenue is equal to government spending", "A tax on income or wealth, paid by the person liable for it", "What the government must pay on money it has borrowed"]}'::jsonb, '{"answer": 1, "explain": "“Balanced budget” means: Tax revenue is equal to government spending"}'::jsonb),
('economics:3-5-fiscal-policy:match:12e5b89d', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Corporation tax”?", "options": ["A direct tax charged on business profits", "Money given to encourage goods with positive externalities", "Tax revenue exceeds government spending", "Tax revenue is equal to government spending"]}'::jsonb, '{"answer": 0, "explain": "“Corporation tax” means: A direct tax charged on business profits"}'::jsonb),
('economics:3-5-fiscal-policy:match:27983eb4', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Excise duty”?", "options": ["An indirect tax on goods like tobacco, alcohol and fuel", "Outcomes a policy causes that the government did not intend", "Money given to encourage goods with positive externalities", "Each round of spending becomes income, which is spent again"]}'::jsonb, '{"answer": 0, "explain": "“Excise duty” means: An indirect tax on goods like tobacco, alcohol and fuel"}'::jsonb),
('economics:3-5-fiscal-policy:match:29d46771', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Multiplier effect”?", "options": ["Each round of spending becomes income, which is spent again", "Outcomes a policy causes that the government did not intend", "The government''s choices about taxation and spending", "A direct tax charged on business profits"]}'::jsonb, '{"answer": 0, "explain": "“Multiplier effect” means: Each round of spending becomes income, which is spent again"}'::jsonb),
('economics:3-5-fiscal-policy:match:c0d6e465', 'economics', 'economics:3-5-fiscal-policy', '3.5 Fiscal Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Subsidy”?", "options": ["Outcomes a policy causes that the government did not intend", "Tax revenue is equal to government spending", "The government''s choices about taxation and spending", "Money given to encourage goods with positive externalities"]}'::jsonb, '{"answer": 3, "explain": "“Subsidy” means: Money given to encourage goods with positive externalities"}'::jsonb),
