('economics:3-6-monetary-policy:match:9ccbc318', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Monetary policy”?", "options": ["The UK''s central bank, which operates monetary policy independently of government", "The 9-member Bank of England committee that sets the base rate", "Using interest rates, the money supply and exchange rates to influence economic activity", "The Bank of England creates money electronically to buy assets and raise the money supply"]}'::jsonb, '{"answer": 2, "explain": "“Monetary policy” means: Using interest rates, the money supply and exchange rates to influence economic activity"}'::jsonb),
('economics:3-6-monetary-policy:match:b7a8a5b1', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bank of England”?", "options": ["The UK''s central bank, which operates monetary policy independently of government", "Using taxation and government spending, controlled by the government rather than the Bank of England", "The 9-member Bank of England committee that sets the base rate", "The Bank of England sells assets, or lets bonds mature, reducing the money supply"]}'::jsonb, '{"answer": 0, "explain": "“Bank of England” means: The UK''s central bank, which operates monetary policy independently of government"}'::jsonb),
('economics:3-6-monetary-policy:match:41e004d8', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Monetary Policy Committee (MPC)”?", "options": ["A mortgage whose interest payments rise and fall directly with the base rate", "The type of inflation that higher interest rates directly ease, by reducing total demand", "The Bank of England creates money electronically to buy assets and raise the money supply", "The 9-member Bank of England committee that sets the base rate"]}'::jsonb, '{"answer": 3, "explain": "“Monetary Policy Committee (MPC)” means: The 9-member Bank of England committee that sets the base rate"}'::jsonb),
('economics:3-6-monetary-policy:match:50a7cfc7', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Base rate”?", "options": ["Lower interest rates can improve this by making exports cheaper and imports dearer", "The rate of interest at which the Bank of England lends to commercial banks", "Using interest rates, the money supply and exchange rates to influence economic activity", "The Bank of England creates money electronically to buy assets and raise the money supply"]}'::jsonb, '{"answer": 1, "explain": "“Base rate” means: The rate of interest at which the Bank of England lends to commercial banks"}'::jsonb),
('economics:3-6-monetary-policy:match:e8945fda', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Inflation target”?", "options": ["The UK''s target of 2% inflation, with a margin of 1% either way", "The Bank of England creates money electronically to buy assets and raise the money supply", "Lower interest rates can improve this by making exports cheaper and imports dearer", "Higher UK interest rates attract foreign funds, so the pound tends to appreciate"]}'::jsonb, '{"answer": 0, "explain": "“Inflation target” means: The UK''s target of 2% inflation, with a margin of 1% either way"}'::jsonb),
('economics:3-6-monetary-policy:match:2af4b0ed', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quantitative easing (QE)”?", "options": ["The Bank of England creates money electronically to buy assets and raise the money supply", "The 9-member Bank of England committee that sets the base rate", "The UK''s target of 2% inflation, with a margin of 1% either way", "Lower interest rates can improve this by making exports cheaper and imports dearer"]}'::jsonb, '{"answer": 0, "explain": "“Quantitative easing (QE)” means: The Bank of England creates money electronically to buy assets and raise the money supply"}'::jsonb),
('economics:3-6-monetary-policy:match:af8441dc', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quantitative tightening (QT)”?", "options": ["The UK''s target of 2% inflation, with a margin of 1% either way", "Using taxation and government spending, controlled by the government rather than the Bank of England", "Using interest rates, the money supply and exchange rates to influence economic activity", "The Bank of England sells assets, or lets bonds mature, reducing the money supply"]}'::jsonb, '{"answer": 3, "explain": "“Quantitative tightening (QT)” means: The Bank of England sells assets, or lets bonds mature, reducing the money supply"}'::jsonb),
('economics:3-6-monetary-policy:match:f5a69a44', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Demand-pull inflation”?", "options": ["Using interest rates, the money supply and exchange rates to influence economic activity", "The UK''s target of 2% inflation, with a margin of 1% either way", "Lower interest rates can improve this by making exports cheaper and imports dearer", "The type of inflation that higher interest rates directly ease, by reducing total demand"]}'::jsonb, '{"answer": 3, "explain": "“Demand-pull inflation” means: The type of inflation that higher interest rates directly ease, by reducing total demand"}'::jsonb),
('economics:3-6-monetary-policy:match:e0cd2eb8', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fiscal policy”?", "options": ["How optimistic people feel about the economy; can blunt or boost the effect of a rate change", "Using taxation and government spending, controlled by the government rather than the Bank of England", "The UK''s target of 2% inflation, with a margin of 1% either way", "A mortgage whose interest payments rise and fall directly with the base rate"]}'::jsonb, '{"answer": 1, "explain": "“Fiscal policy” means: Using taxation and government spending, controlled by the government rather than the Bank of England"}'::jsonb),
('economics:3-6-monetary-policy:match:4611566a', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Exchange rate effect”?", "options": ["Higher UK interest rates attract foreign funds, so the pound tends to appreciate", "The Bank of England sells assets, or lets bonds mature, reducing the money supply", "A mortgage whose interest payments rise and fall directly with the base rate", "How optimistic people feel about the economy; can blunt or boost the effect of a rate change"]}'::jsonb, '{"answer": 0, "explain": "“Exchange rate effect” means: Higher UK interest rates attract foreign funds, so the pound tends to appreciate"}'::jsonb),
