('economics:3-6-monetary-policy:match:3779daad', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer confidence”?", "options": ["The Bank of England creates money electronically to buy assets and raise the money supply", "The rate of interest at which the Bank of England lends to commercial banks", "How optimistic people feel about the economy; can blunt or boost the effect of a rate change", "The 9-member Bank of England committee that sets the base rate"]}'::jsonb, '{"answer": 2, "explain": "“Consumer confidence” means: How optimistic people feel about the economy; can blunt or boost the effect of a rate change"}'::jsonb),
('economics:3-6-monetary-policy:match:0c8dbd53', 'economics', 'economics:3-6-monetary-policy', '3.6 Monetary Policy', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Variable-rate mortgage”?", "options": ["Using interest rates, the money supply and exchange rates to influence economic activity", "Lower interest rates can improve this by making exports cheaper and imports dearer", "A mortgage whose interest payments rise and fall directly with the base rate", "The type of inflation that higher interest rates directly ease, by reducing total demand"]}'::jsonb, '{"answer": 2, "explain": "“Variable-rate mortgage” means: A mortgage whose interest payments rise and fall directly with the base rate"}'::jsonb),
('economics:3-7-supply-side-policies:exam:72e02123', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Why is this an example of a supply side policy?", "options": ["Journey times will be improved for people travelling to work", "Many construction companies will achieve greater profits", "The £50bn could have been used to reduce the level of direct taxation", "There will be an increased demand for imported building materials"], "caseStudy": "<p>The government spends £50bn on a new railway line linking some of the country''s largest cities.</p>", "hint": "Find the option that raises the economy''s productive CAPACITY. The others are demand-side profits, an opportunity cost, and a knock-on import effect — not the supply-side mechanism itself.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Journey times will be improved for people travelling to work</strong></p>\n<ul>\n<li>Faster journeys directly raise the economy''s productive capacity — workers reach jobs faster and firms move goods faster. Builder profits (B) are a demand-side effect of the spending; the foregone tax cut (C) is an opportunity cost, not the mechanism; and import demand (D) is also a demand-side knock-on.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly identified the correct answer (A).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:exam:626f5747', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q4", "question": "Why may this decision encourage Amari to look for a job?", "options": ["Amari will have a lower disincentive to work", "Amari will pay less tax if he gets a job", "More job vacancies will be advertised", "Trade union power will decrease"], "caseStudy": "<p>Amari is unemployed and not looking for a job. He receives £72 a week in benefits. As part of the government''s supply side policies, it has announced that unemployment benefits will be reduced.</p>", "hint": "Lower benefits shrink the gap between being unemployed and being in work — reducing the DISINCENTIVE to take a job. The other options either don''t follow from a benefits cut, or are unrelated policies.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Amari will have a lower disincentive to work</strong></p>\n<ul>\n<li>Cutting benefits narrows the gap between out-of-work income and in-work income, reducing the disincentive to take a job. Tax paid, vacancy numbers, and trade union power are not direct consequences of this specific policy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly answered A.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:exam:8ec0a4ef', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q5", "question": "One likely benefit of supply side policy is to improve a country''s balance of payments. This is because supply side policy can", "options": ["improve the productivity of the UK labour force", "lead to a higher rate of inflation in the UK", "lead to higher consumption by UK consumers", "mean free trade agreements are cancelled"], "hint": "Trace the chain to EXPORTS: higher productivity → lower costs → more competitive UK goods abroad → more exports → better balance of payments. Higher inflation would make exports LESS competitive.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — improve the productivity of the UK labour force</strong></p>\n<ul>\n<li>Higher productivity lowers costs, making UK goods more competitive abroad and raising exports. Higher inflation (B) would make exports LESS competitive, not more.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly answered A.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:exam:68e94b2f', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q7", "question": "The government decides to increase spending on public transport. Which of the following could be considered an opportunity cost of this decision?", "options": ["A decrease in direct taxation", "A decrease in spending on education", "A decrease in the budget deficit", "A decrease in unemployment"], "hint": "Opportunity cost is the next best alternative GIVEN UP. Which option is something the government could have spent that money on instead, but now can''t?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — A decrease in spending on education</strong></p>\n<ul>\n<li>If the government spends more on transport, it may have less to spend on education instead — the classic opportunity cost. A tax cut, a smaller deficit, and lower unemployment are not things given UP by this decision; they are unrelated or even positive side-effects.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:exam:8488add6', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q8", "question": "The government is concerned about the level of monopoly power in the UK social media industry. Any policy introduced to reduce this monopoly power would be an example of", "options": ["fiscal policy", "monetary policy", "supply side policy", "trade policy"], "hint": "Policies that promote competition and remove barriers to efficient markets are a classic supply-side tool — like the CMA blocking mergers.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — supply side policy</strong></p>\n<ul>\n<li>Reducing monopoly power promotes competition, which is a supply-side policy aimed at making markets work more efficiently — not a tax, interest rate, or trade measure.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:exam:9c8ae1b4', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q9", "question": "Which of these is an example of a supply side policy?", "options": ["Changing interest rates", "Encouraging bank lending", "Imposing taxes on imports", "Lowering unemployment benefits"], "hint": "Interest rates and bank lending are monetary policy tools; import taxes are trade policy. Only one option changes the incentive to WORK.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — Lowering unemployment benefits</strong></p>\n<ul>\n<li>Lower benefits increase the incentive to take a job, raising labour supply — a classic supply-side policy. The other three are monetary or trade policy tools.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:exam:e62bcbd9', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Which of the following is an example of supply-side policy?", "options": ["Lowering the rate of price rises", "National defence expenditure", "Raising interest rates", "Reducing direct taxes on workers"], "hint": "''Lowering the rate of price rises'' is an OUTCOME (price stability), not a policy. Raising rates is monetary policy. National defence spending doesn''t target productive capacity.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Reducing direct taxes on workers</strong></p>\n<ul>\n<li>Cutting income tax raises the incentive to work, directly targeting labour supply. Option A describes an outcome, not a policy; raising rates is monetary policy; defence spending is not aimed at productive capacity.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:exam:3f32deae', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'exam', 'mcq', 1, '{"num": "Q12", "question": "Which one of the following is a supply side policy the UK government could use to boost the economy?", "options": ["Increase economic growth", "Increase foreign investment", "Increase investment in infrastructure", "Increase unemployment benefits"], "hint": "Growth and foreign investment are OUTCOMES/goals, not policies themselves. Raising benefits works against supply-side aims. Only one option is an actual policy TOOL that raises productive capacity.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Increase investment in infrastructure</strong></p>\n<ul>\n<li>Infrastructure investment is an actual policy tool that lowers costs and raises productive capacity. ''Increase economic growth'' and ''increase foreign investment'' are outcomes/goals, not policies; raising benefits works against the usual supply-side aim of increasing work incentives.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-7-supply-side-policies:mcq:0be32d59', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "Supply-side policies aim primarily to...", "options": ["Reduce the money supply", "Increase the economy''s productive capacity", "Fix the exchange rate", "Increase government spending on benefits"]}'::jsonb, '{"answer": 1, "explain": "Supply-side policies raise potential output/productive capacity, unlike fiscal or monetary policy which mainly manage demand."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:a45e5d41', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of a supply-side policy?", "options": ["Investment in infrastructure", "Raising interest rates", "A rise in government spending on defence", "Increasing unemployment benefits"]}'::jsonb, '{"answer": 0, "explain": "Infrastructure investment raises firms'' productive capacity by lowering costs. Raising rates is monetary policy; the other two do not raise supply."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:bec59254', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "How does cutting corporation tax act as a supply-side policy?", "options": ["Firms keep more profit, giving them more finance to invest in productive capacity", "It reduces the level of aggregate demand", "It directly lowers the price of imports", "It increases government spending on infrastructure"]}'::jsonb, '{"answer": 0, "explain": "Lower corporation tax leaves firms with more retained profit, which can fund investment that raises the economy''s capacity to produce."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:5c47379a', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "A cut in income tax is intended to increase the labour supply because...", "options": ["It reduces the cost of imported goods", "Workers keep more of what they earn, incentivising work", "It directly creates new jobs in the public sector", "It lowers the exchange rate"]}'::jsonb, '{"answer": 1, "explain": "In effect, an income tax cut acts like a pay rise without raising costs to firms, incentivising more people to work or work longer hours."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:a6f4c359', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "Reducing the power of trade unions is intended to...", "options": ["Increase the number of strikes", "Raise the level of unemployment benefits", "Make it easier for firms to keep wages, and therefore costs, down", "Directly increase government tax revenue"]}'::jsonb, '{"answer": 2, "explain": "Restricting collective bargaining power makes it easier for firms to hold down real wages, reducing costs and supporting supply."}'::jsonb)
